# Exercício 7 - Histórico de Uso da CPU (Logger em Arquivo)\n\n# importo as bibliotecas\nimport psutil      # para pegar dados de CPU\nimport datetime    # para timestamp (data e hora)\nimport time        # para sleep (pausar)\nimport os          # para limpar tela\n\n# arquivo onde vou salvar os logs\narquivo_log = \"cpu_log.txt\"\n\n# limpo a tela\nos.system(\"cls\")\n\nprint(\"=\"*60)\nprint(\"       HISTÓRICO DE USO DA CPU\")\nprint(f\"Salvando em: {arquivo_log}\")\nprint(\"=\"*60)\nprint(\"Coletando dados... Pressione Ctrl+C para interromper\\n\")\n\ntry:\n    while True:\n        # obtenho o horário atual\n        # datetime.datetime.now() retorna a data e hora atual\n        agora = datetime.datetime.now()\n\n        # converto para string formatada\n        # strftime() formata a data/hora conforme indicado\n        # %Y-%m-%d = YYYY-MM-DD (ano-mês-dia)\n        # %H:%M:%S = HH:MM:SS (hora:minuto:segundo)\n        timestamp = agora.strftime(\"%Y-%m-%d %H:%M:%S\")\n\n        # obtenho o uso da CPU\n        # interval=1 aguarda 1 segundo para medir\n        # percpu=False retorna apenas o total (não por núcleo)\n        cpu_percent = psutil.cpu_percent(interval=1, percpu=False)\n\n        # monto a linha do log\n        # formato: DATA HORA - CPU: XX%\n        linha_log = f\"{timestamp} - CPU: {cpu_percent:.1f}%\"\n\n        try:\n            # abro o arquivo em modo \"append\" (adicionar)\n            with open(arquivo_log, \"a\") as arquivo:\n                # escrevo a linha no arquivo\n                arquivo.write(linha_log + \"\\n\")\n\n            # exibo na tela o que foi salvo\n            print(f\"[{timestamp}] CPU: {cpu_percent:.1f}%\")\n\n        except IOError as e:\n            # se houver erro ao salvar, informo\n            print(f\"Erro ao salvar no arquivo: {e}\")\n\n        # aguardo 5 segundos antes de próxima coleta\n        print(\"Próxima medição em 5 segundos...\\n\")\n        time.sleep(5)\n\nexcept KeyboardInterrupt:\n    # se pressionar Ctrl+C\n    print(\"\\n\\nPrograma interrompido pelo usuário.\")\n    print(f\"Logs foram salvos em: {arquivo_log}\")\n\n# Anotações:\n# - datetime.datetime.now() retorna um objeto datetime com data/hora atual\n#   * formato: 2026-02-24 19:35:45.123456\n# - strftime(formato) converte datetime em string formatada\n#   * %Y = ano com 4 dígitos (2026)\n#   * %m = mês com 2 dígitos (02)\n#   * %d = dia com 2 dígitos (24)\n#   * %H = hora em 24h (19)\n#   * %M = minuto (35)\n#   * %S = segundo (45)\n#   * Lista completa em: python strftime docs\n# - (arquivo, \"a\") abre em modo append = adiciona ao final do arquivo\n# - with open(arquivo) abre arquivo e AUTOMATICAMENTE fecha no final\n#   * melhor prática do que abrir e fechar manualmente\n# - arquivo.write(texto) escreve a string no arquivo\n# - try/except IOError capita erros de leitura/escrita de arquivo\n# - psutil.cpu_percent(interval=1) mede o uso de CPU em 1 segundo\n# - logging de dados é útil para análise histórica de performance\n